9134 bool BoUpSLP::isFullyVectorizableTinyTree(bool ForReduction) const {
9135   LLVM_DEBUG(dbgs() << "SLP: Check whether the tree with height "
9136                     << VectorizableTree.size() << " is fully vectorizable .\n");
9137 
9138   auto &&AreVectorizableGathers = [this](const TreeEntry *TE, unsigned Limit) {
9139     SmallVector<int> Mask;
9140     return TE->State == TreeEntry::NeedToGather &&
9141            !any_of(TE->Scalars,
9142                    [this](Value *V) { return EphValues.contains(V); }) &&
9143            (allConstant(TE->Scalars) || isSplat(TE->Scalars) ||
9144             TE->Scalars.size() < Limit ||
9145             ((TE->getOpcode() == Instruction::ExtractElement ||
9146               all_of(TE->Scalars, IsaPred<ExtractElementInst, UndefValue>)) &&
9147              isFixedVectorShuffle(TE->Scalars, Mask)) ||
9148             (TE->State == TreeEntry::NeedToGather &&
9149              TE->getOpcode() == Instruction::Load && !TE->isAltShuffle()));
9150   };
9151 
9152   // We only handle trees of heights 1 and 2.
9153   if (VectorizableTree.size() == 1 &&
9154       (VectorizableTree[0]->State == TreeEntry::Vectorize ||
9155        (ForReduction &&
9156         AreVectorizableGathers(VectorizableTree[0].get(),
9157                                VectorizableTree[0]->Scalars.size()) &&
9158         VectorizableTree[0]->getVectorFactor() > 2)))
9159     return true;
9160 
9161   if (VectorizableTree.size() != 2)
9162     return false;
9163 
9164   // Handle splat and all-constants stores. Also try to vectorize tiny trees
9165   // with the second gather nodes if they have less scalar operands rather than
9166   // the initial tree element (may be profitable to shuffle the second gather)
9167   // or they are extractelements, which form shuffle.
9168   SmallVector<int> Mask;
9169   if (VectorizableTree[0]->State == TreeEntry::Vectorize &&
9170       AreVectorizableGathers(VectorizableTree[1].get(),
9171                              VectorizableTree[0]->Scalars.size()))
9172     return true;
9173 
9174   // Gathering cost would be too much for tiny trees.
9175   if (VectorizableTree[0]->State == TreeEntry::NeedToGather ||
9176       (VectorizableTree[1]->State == TreeEntry::NeedToGather &&
9177        VectorizableTree[0]->State != TreeEntry::ScatterVectorize &&
9178        VectorizableTree[0]->State != TreeEntry::StridedVectorize))
9179     return false;
9180 
9181   return true;
9182 }
